+            emergency_grants: BTreeMap::new(),
+            pending_post_reviews: BTreeSet::new(),
+            emergency_grant_only_requests: BTreeSet::new(),
+            request_sequence: 0,
+            request_ttl_ns: DEFAULT_ESCROW_REQUEST_TTL_NS,
