+
+    pub fn records(&self) -> &BTreeMap<String, CapabilityEscrowRecord> {
+        &self.records
+    }
+
+    pub fn receipts(&self) -> &[CapabilityEscrowDecisionReceipt] {
+        &self.receipts
+    }
+
+    pub fn events(&self) -> &[CapabilityEscrowDecisionEvent] {
