+    }
+
+    pub fn active_emergency_grants(&self) -> Vec<EmergencyGrantArtifact> {
+        self.emergency_grants
+            .values()
+            .filter(|grant| !grant.revoked)
+            .map(|grant| grant.artifact.clone())
+            .collect()
